const postCategories = [
  {
    id: 'education',
    name: 'Education for Software Business Owners',
    description: 'Educational content that teaches software business owners practical strategies, frameworks, and insights to grow and manage their businesses more effectively.',
    tone: 'Authoritative yet approachable. Use real-world examples and actionable takeaways.',
    examples: [
      '5 metrics every SaaS founder should track weekly',
      'Why most software businesses fail at pricing — and how to fix it',
      'The build vs buy decision: a framework for software business owners'
    ]
  },
  {
    id: 'thought_leadership',
    name: 'AI/Software Industry Thought Leadership',
    description: 'Content that positions the author as a forward-thinking leader in the AI and software industry. Shares bold opinions, predictions, trends, and original perspectives.',
    tone: 'Confident, visionary, slightly contrarian. Back claims with reasoning or experience.',
    examples: [
      'AI won\'t replace software engineers — but it will replace software companies that ignore it',
      'The next wave of SaaS will be built by domain experts, not developers',
      'Why I think the AI agent hype is actually understated'
    ]
  },
  {
    id: 'cta_consultation',
    name: 'Call-to-Action — Book a Consultation',
    description: 'Content that provides genuine value while naturally leading business owners to book a software/AI consultation. Highlights pain points, shares quick wins, and invites readers to go deeper with a call.',
    tone: 'Empathetic, solution-oriented, helpful. The CTA should feel like a natural next step, not a hard sell.',
    examples: [
      'If your software project has stalled, here are 3 questions to ask yourself (and when to call in help)',
      'I reviewed 20 failed AI implementations last quarter. Here\'s the #1 mistake — and how to avoid it',
      'Not sure if AI is right for your business? Here\'s a 2-minute self-assessment'
    ]
  }
];

// Randomly select a category (or rotate based on day-of-week)
const dayOfWeek = new Date().getDay(); // 0=Sun, 1=Mon, ...
let selectedIndex;
if (dayOfWeek === 1) selectedIndex = 0;       // Monday → Education
else if (dayOfWeek === 3) selectedIndex = 1;   // Wednesday → Thought Leadership
else if (dayOfWeek === 5) selectedIndex = 2;   // Friday → CTA
else selectedIndex = Math.floor(Math.random() * 3);

const selected = postCategories[selectedIndex];

return {
  json: {
    selectedCategory: selected,
    allCategories: postCategories,
    selectionReason: `Selected '${selected.name}' based on day-of-week rotation (day=${dayOfWeek}).`
  }
};

