// Parse the 5 ideas from Gemini and score them
const input = $input.first().json;

let ideas;
try {
  // Gemini node outputs vary — try common paths
  let raw;
  if (input.message && input.message.content) {
    raw = input.message.content;
  } else if (input.text) {
    raw = input.text;
  } else if (input.output) {
    raw = input.output;
  } else {
    // Fallback: stringify and search for JSON
    raw = JSON.stringify(input);
  }

  if (typeof raw !== 'string') {
    raw = JSON.stringify(raw);
  }
  const cleaned = raw.replace(/```json\n?|```\n?/g, '').trim();
  ideas = JSON.parse(cleaned).ideas;
} catch (e) {
  throw new Error(`Failed to parse Gemini response: ${e.message}. Raw keys: ${Object.keys(input).join(', ')}`);
}

// ─── SCORING CRITERIA ───
function scoreIdea(idea) {
  const hook = idea.hook.toLowerCase();
  let scores = {};

  // 1. Curiosity Gap
  scores.curiosity = 5;
  if (hook.includes('why') || hook.includes('how') || hook.includes('what if')) scores.curiosity += 2;
  if (hook.includes('?')) scores.curiosity += 1;
  if (hook.includes('secret') || hook.includes('mistake') || hook.includes('truth') || hook.includes('myth')) scores.curiosity += 2;

  // 2. Specificity
  scores.specificity = 5;
  if (/\d+/.test(hook)) scores.specificity += 3;
  if (hook.includes('example') || hook.includes('case study') || hook.includes('framework')) scores.specificity += 2;

  // 3. Emotional Trigger
  scores.emotion = 5;
  const emotionWords = ['fail', 'mistake', 'wrong', 'surprising', 'shocking', 'love', 'hate', 'afraid', 'bold', 'unpopular', 'controversial', 'honest', 'hard truth', 'painful'];
  emotionWords.forEach(w => { if (hook.includes(w)) scores.emotion += 1; });
  scores.emotion = Math.min(scores.emotion, 10);

  // 4. Relevance to Target Audience
  scores.relevance = 5;
  const audienceWords = ['software', 'saas', 'ai', 'business', 'founder', 'ceo', 'startup', 'product', 'tech', 'engineer', 'developer', 'client', 'revenue', 'growth', 'scale'];
  audienceWords.forEach(w => { if (hook.includes(w)) scores.relevance += 1; });
  scores.relevance = Math.min(scores.relevance, 10);

  // 5. Scroll-stop Power
  scores.scrollStop = 5;
  if (hook.length < 80) scores.scrollStop += 2;
  if (hook.startsWith('i ') || hook.startsWith('stop') || hook.startsWith('nobody')) scores.scrollStop += 2;
  if (/[—–:]/.test(hook)) scores.scrollStop += 1;

  // Weighted total
  const weights = { curiosity: 0.25, specificity: 0.20, emotion: 0.20, relevance: 0.20, scrollStop: 0.15 };
  let totalScore = 0;
  for (const [k, w] of Object.entries(weights)) {
    totalScore += scores[k] * w;
  }

  return {
    ...idea,
    scores,
    totalScore: Math.round(totalScore * 100) / 100
  };
}

const scoredIdeas = ideas.map(scoreIdea).sort((a, b) => b.totalScore - a.totalScore);
const bestIdea = scoredIdeas[0];

return {
  json: {
    bestIdea,
    allScoredIdeas: scoredIdeas,
    selectionSummary: `Selected idea #${bestIdea.id} with score ${bestIdea.totalScore}/10: "${bestIdea.hook}"`
  }
};

