// Parse and score graphic ideas
const input = $input.first().json;
let graphicData;
try {
  // Gemini node outputs vary — try common paths
  let raw;
  if (input.message && input.message.content) {
    raw = input.message.content;
  } else if (input.text) {
    raw = input.text;
  } else if (input.output) {
    raw = input.output;
  } else {
    raw = JSON.stringify(input);
  }

  if (typeof raw !== 'string') {
    raw = JSON.stringify(raw);
  }
  const cleaned = raw.replace(/```json\n?|```\n?/g, '').trim();
  graphicData = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse graphic ideas: ${e.message}. Raw keys: ${Object.keys(input).join(', ')}`);
}

const ideas = graphicData.graphic_ideas;

// Score graphic ideas
function scoreGraphic(idea) {
  let score = 5;

  // Simplicity bonus (minimalist/clean styles score higher on LinkedIn)
  const simpleStyles = ['minimalist', 'clean', 'bold typography', 'simple'];
  if (simpleStyles.some(s => idea.visual_style.toLowerCase().includes(s))) score += 2;

  // Text overlay bonus (posts with text-on-image get more engagement)
  if (idea.key_text_overlay && idea.key_text_overlay.length > 5 && idea.key_text_overlay.length < 60) score += 2;

  // Specificity of Canva tips (more actionable = better)
  if (idea.canva_tips && idea.canva_tips.length > 40) score += 1;

  return { ...idea, score: Math.min(score, 10) };
}

const scored = ideas.map(scoreGraphic).sort((a, b) => b.score - a.score);
const bestGraphic = scored[0];

// Pull post data from upstream
const postNode = $node['Parse Post Output'].json;

return {
  json: {
    bestGraphicIdea: bestGraphic,
    allScoredGraphics: scored,
    post: postNode.post,
    hashtags: postNode.hashtags,
    category: postNode.category,
    bestIdea: postNode.bestIdea,
    graphicSelectionSummary: `Selected graphic #${bestGraphic.id} (score ${bestGraphic.score}/10): "${bestGraphic.title}"`
  }
};

// ─── ASSEMBLE THE FINAL LINKEDIN POST PACKAGE ───
const data = $input.first().json;

// Calculate a suggested schedule time (next available slot)
const now = new Date();
const scheduleHour = 8; // 8 AM is a good LinkedIn posting time
const scheduledDate = new Date(now);
scheduledDate.setDate(scheduledDate.getDate() + 1); // Schedule for tomorrow
scheduledDate.setHours(scheduleHour, 0, 0, 0);

const finalPackage = {
  // ── Post Content ──
  linkedinPostText: data.post,
  hashtags: data.hashtags,

  // ── Graphic Brief for Canva ──
  graphicBrief: {
    title: data.bestGraphicIdea.title,
    layout: data.bestGraphicIdea.layout,
    textOverlay: data.bestGraphicIdea.key_text_overlay,
    visualStyle: data.bestGraphicIdea.visual_style,
    colorPalette: data.bestGraphicIdea.color_palette,
    canvaTips: data.bestGraphicIdea.canva_tips,
    recommendedSize: '1200x1200px (square) or 1200x628px (landscape)'
  },

  // ── Metadata ──
  category: data.category.name,
  hookLine: data.bestIdea.hook,
  suggestedScheduleTime: scheduledDate.toISOString(),
  suggestedScheduleDisplay: scheduledDate.toLocaleString('en-US', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
    timeZoneName: 'short'
  }),
  status: 'PENDING_GRAPHIC_CREATION',

  // ── Review Checklist ──
  reviewChecklist: [
    'Does the hook grab attention in the first 2 lines?',
    'Is the post authentic and not overly promotional?',
    'Does it provide genuine value to software business owners?',
    'Is the CTA clear (if applicable)?',
    'Have you created the graphic in Canva based on the brief?',
    'Does the graphic complement (not repeat) the post?',
    'Is the scheduled time optimal for your audience timezone?'
  ]
};

return { json: finalPackage };

